var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"얍.","JPN":"やあっ。","ENG":"Yap.","TWN":"嘿。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"나이스 타이밍?","JPN":"ナイスタイミング？","ENG":"Nice timing?","TWN":"來得正好？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네. 완전 나이스 타이밍이에요.","JPN":"はい、ドンピシャです。","ENG":"Yes. Nice timing indeed.","TWN":"是的，絕對來得正好。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"잘못된 거 아닌가 싶었는데 이렇게 도와주러 오시고. 웬일로 이름값 좀 하셨네요?","JPN":"やられたと思っていましたが、こちらを手伝いに来てくれるなんて。今日だけは株が急上昇ですね。","ENG":"I thought maybe something happened to you, but you made it and even helped me out. Maybe sometimes Credere does mean trust.","TWN":"還以為來不了了呢。真是難得，克蕾妲莉終於做出人如其名的事。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레를 모욕하지 마라, 어이-.","JPN":"クレデレをなめるんじゃないぞ、コラ。","ENG":"Do not speak ill of Credere. Arr.","TWN":"不許你這樣說克蕾妲莉。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"웬일이 아니라 매일 이런다, 어이-.","JPN":"今日だけじゃなくて常にだ、コラ。","ENG":"It is not \\"sometimes.\\" Credere is always the icon of trust. Arr.","TWN":"不是難得，克蕾妲莉一直這樣。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네네. 장해요 우리 크레데레.","JPN":"はいはい、よくできました。クレデレちゃん。","ENG":"Yeah, yeah. I'm so proud of you, Credere.","TWN":"好好好，我們克蕾妲莉最棒。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"언니가 진~하게 한 번 안아드릴게요.","JPN":"お姉ちゃんが抱きしめてあげましょうか？","ENG":"Let me give you a biiiiig hug.","TWN":"姊姊我會好～～好抱你一次的。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"힉.","JPN":"ひいっ。","ENG":"*Gasp*","TWN":"唔。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"시그마시그마. 유피가 미쳤습니다.","JPN":"シグマシグマ、ユピがご乱心です。","ENG":"Sigma-Sigma. Yuppie's gone crazy.","TWN":"西格瑪西格瑪。悠菲瘋了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"싸우다가 머리를 세게 얻어맞은 건가요?","JPN":"戦闘で頭を強く打ったんでしょうか？","ENG":"Did someone hit her head while fighting?","TWN":"打架的時候腦子被狠狠地打壞了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"후후.","JPN":"ふふ。","ENG":"Ha hah.","TWN":"呵呵。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"…미스터 쮸빕. 아무래도 크레데레가 너무 늦은 것 같습니다.","JPN":"……ミスター・チュピー。どうやらクレデレの到着が遅すぎたようです。","ENG":"...Mr. Squirty, it seems like Credere was too late.","TWN":"……咻咻先生。看來克蕾妲莉來得太晚了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"이렇게 된 이상 어쩔 수 없죠.","JPN":"こうなったら、もう仕方ないですね。","ENG":"It seems that there is no other choice.","TWN":"既然這樣，那也沒辦法了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"장례지도사 자격증을 보유한 크레데레가 두 분을 천국으로 모시겠습니다.","JPN":"葬儀屋の資格を持つクレデレが、お二方をあの世まで送ってあげましょう。","ENG":"As a certified undertaker, Credere shall lead you both to the afterlife.","TWN":"持有禮儀師資格證的克蕾妲莉將送你們二位上路。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레는 장수할 테니 천년 정도 뒤에 다시 만나죠.","JPN":"クレデレは長生きすると思うので、次会うのはきっと千年後ですね。","ENG":"You will see Credere in about a thousand years, as Credere will live long and prosper.","TWN":"克蕾妲莉會長壽的，一千年之後再見吧。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"그럼 아디오스-.","JPN":"では、アディオス。","ENG":"Adios.","TWN":"那就拜拜啦——"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"뭐라는 거야. 시그마가 든 이거 안 보여요?","JPN":"何言ってるんですか。シグマが何を持っているか、見えませんか？","ENG":"Whatever. Credere, did you see what Sigma is holding?","TWN":"你說什麼呢。沒看到西格瑪拿著這個嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"보세요. 저 아줌마를 상대로 제대로 지켜냈다고요.","JPN":"見てくださいよ。あのおばさん相手に、これをちゃんと守り抜いたんですよ。","ENG":"Look. She kept that safe against the Vice President.","TWN":"看吧，我們成功從大嬸手裡保住這個箱子了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"이건?","JPN":"これは？","ENG":"Does that mean–","TWN":"這是……？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"응, 맞아!","JPN":"うん、そうだよ！","ENG":"Yes!","TWN":"是，沒錯！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"보물찾기는 끝이다, 얼!","JPN":"お宝探しはこれで終了だ、ARRR！","ENG":"The treasure hunt is over, yarr!","TWN":"尋寶結束了，唷呵！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"마귀상어를 물리친 시그마 해적단의 승리야!!","JPN":"ババアサメを倒したシグマ海賊団の勝利だよ！！","ENG":"The Sigma Pirates defeated the wicked shark and are victorious!","TWN":"擊敗魔鬼鯊的西格瑪海盜團勝利啦！！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"드디어… 드디어 이 지긋지긋한 빚쟁이 생활과는 안녕이에요.","JPN":"ついに……この泥沼借金生活にも終わりが来るんですね。","ENG":"Finally... Finally, I can say goodbye to my debt-ridden life.","TWN":"終於……終於可以告別討厭的債務生活了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"저희 이제 부자라고요! 돌아가는 길에 헬리콥터나 부를까요? 아니면 비행기?","JPN":"これでお金持ちデビューですね！　帰りはヘリでも呼びましょうか？　それともプライベートジェット？","ENG":"We're rich now! Should we call a chopper to get us back? Or maybe a private jet?","TWN":"我們現在可是富翁了！要不做直升機回去吧？或者私人飛機？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"안됩니다 유피. 해적이면 배를 타야죠.","JPN":"ダメです、ユピ。海賊は海賊らしく船に乗らないと。","ENG":"No, Yuppie. A pirate should always board a ship.","TWN":"不行，悠菲。既然是海盜，就得坐船。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"기왕이면 뱃머리에 크레데레를 본떠 만든 선수상이 있는 게 좋겠습니다.","JPN":"せっかくなら船首はクレデレの象で飾りたいですね。","ENG":"Preferably a ship with a figurehead created in the image of Credere.","TWN":"這樣的話，船頭最好還得有個克蕾妲莉樣子的雕像。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L44_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"마음대로 하세요. 각자 하고 싶은 거 다 하자고요!","JPN":"それは好きにしてもいいですよ。みんながやりたいことを全部やっちゃいましょう！","ENG":"Do whatever you want. We can all do whatever we want!","TWN":"你開心就好，現在大家想做什麼就做什麼！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"선장님. 그럼 저희 상자 안에 뭐가 들었는지-","JPN":"船長、では箱の中身の確認を……","ENG":"Now, then. Captain, let's see what's in the chest–","TWN":"船長，我們來看看箱子裡是什麼吧——"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"응? 저건 뭐야?","JPN":"ん？　あれは何？","ENG":"Huh? What's that?","TWN":"嗯？那是什麼？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"안… 돼.","JPN":"ダ……メ。","ENG":"No...","TWN":"別……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"상자를 열어서는 안 돼!!!","JPN":"開けちゃダメ！！！","ENG":"DON'T OPEN THE CHEST!!!","TWN":"別打開那個箱子！！！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_WHIP"},{"id":"L50_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"꺄아아아아악!!","JPN":"きゃああぁぁぁぁぁっ！！","ENG":"Eeeeek!","TWN":"啊啊啊啊啊！！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"으그그그…! 이, 이거 놔!","JPN":"ううううっ！　は、放して！","ENG":"Nghhh! L-let go of me!","TWN":"哇啊啊啊……！放開……放開我呀！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"내놔. 빨리 내놓으란 말이야!","JPN":"よこせ、それをよこしなさい！","ENG":"Give it. GIVE IT TO ME!","TWN":"給我。把它給我！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"으으… 유피-!","JPN":"うう……ユピ！","ENG":"Ngh... Yuppie!","TWN":"呃呃……悠菲，接著——！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"엑.","JPN":"げっ。","ENG":"Eck.","TWN":"欸。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"부, 부사장님? 일단 진정 좀 하세요.","JPN":"ふ、副社長？　落ち着いてください。","ENG":"Uh, Vice President? Why don't you calm down a bit.","TWN":"副、副總？先冷靜一下。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"하아… 하아…….","JPN":"はあ……はあ……","ENG":"*Huff* *Huff*","TWN":"呼……呼……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그래요. 침착하게 쉼 호흡 좀 하시면서-","JPN":"そうです。ゆっくり深呼吸をして……","ENG":"Yeah. Take a deep breath and stay calm–","TWN":"好的。冷靜下來，深呼吸幾次——"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"내놓으라고-!!","JPN":"はやくよこしなさい！！","ENG":"GIVE IT TO ME!!!","TWN":"還給我——!!"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"끼야아아악!","JPN":"きゃあああっ！！","ENG":"Kyaaaaah!","TWN":"啊啊啊啊——！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"오, 오지 마. 오면 이거 확 열어버릴 줄 알아!","JPN":"こ、来ないでください。じゃないとこの場で開けちゃいますよ！","ENG":"D-don't come any closer. I'm going to open this!","TWN":"別，別過來。你再過來我就把箱子打開了！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"침착하시죠, 유피 양. 상자를 열어봤자 서로 좋을 게 없습니다.","JPN":"落ち着いてください、ユピさん。箱を開けても、お互いにとって何一ついいことはありません。","ENG":"Calm down, Yuppie. It won't do either of us any good if you open that chest.","TWN":"冷靜點，悠菲。打開箱子對我們都沒有好處。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"죽일 듯이 달려와놓고서 이제 와서 그런 말하기예요?","JPN":"あんな必死によこせと叫んでおいて、そんなことを言われても……！","ENG":"You were just about to tear me apart to get to the chest. You can't act all calm now.","TWN":"之前還拼命追殺我，現在又說這種話？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"거기서 한 발자국이라도 움직였다간 이거 확 열어버릴 줄 알아요!","JPN":"そこを一歩でも動いたら、すぐに開けますからね！","ENG":"I'm going to open this if you come any closer!","TWN":"你要是敢動一步，我就立刻把它打開！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"좋습니다. 여시죠.","JPN":"いいでしょう、どうぞ。","ENG":"Fine. Open it, then.","TWN":"好的，那就打開吧。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"蛤？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"본인이 불행을 자처하겠다는데 제가 말려서 뭐하겠습니까?","JPN":"あなたがそこまでして不幸を望むなら、私にはもう止める理由はありません。","ENG":"If you wish to bring misfortune to yourself, who am I to stop you?","TWN":"地獄無門你偏要闖，我又何必阻止呢？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"전 분명 말렸습니다. 이렇게까지 했는데 상자를 열겠다면 어쩔 수 없죠.","JPN":"私はちゃんと止めましたが、それでも開けるというのなら、どうぞお好きに。","ENG":"I already tried to stop you. If, after everything, you still want to open the chest, then I have no choice.","TWN":"我明明已經勸過你，如果你執意要打開箱子，那我也沒辦法。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"어… 그게.","JPN":"ええと、その……","ENG":"Err... well.","TWN":"呃，那個。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"잘 생각해보세요, 유피 양. 정말 평범한 상자 하나에 태스크포스가 움직였겠습니까?","JPN":"よく考えてみてください、ユピさん。ただの箱一つに、タスクフォースが出動すると思いますか？","ENG":"Think carefully, Yuppie. Do you really think a TASKFORCE would've been deployed for one ordinary treasure chest?","TWN":"好好想想，悠菲。公司真的會因為一個普通的箱子就動用特遣隊嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"역사가 증명하듯 보물이 불러오는 건 행운만이 아니지요.","JPN":"歴史も見ても明らかですが、お宝は幸運だけでなく、災いでもあります。","ENG":"History proved and proved itself again that treasure does not always lead to positive consequences.","TWN":"歷史證明，寶物帶來的不僅僅是幸運。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그 모든 걸 감당할 자신이 있다면 상자를 열어도 상관없습니다.","JPN":"何があっても受け入れる心の準備ができているのなら、止めはしません。","ENG":"You are welcome to open that chest if you think you can handle the outcome.","TWN":"如果你有信心承擔這一切，那就打開箱子吧。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"어쩌자는 건데요, 그럼?","JPN":"つまり、何が言いたいんですか？","ENG":"What do you propose, then?","TWN":"那你想怎麼辦呢？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"지금 상자에는 흉악한 저주가 걸려있습니다.","JPN":"その箱には禍々しい呪いがかけられています。","ENG":"The chest is currently under a terrible curse.","TWN":"現在箱子上有一個兇惡的詛咒。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그것만 해결되면 상자를 돌려 드린다고 약속하죠.","JPN":"それが無事に解けたら、箱はお返しするとお約束します。","ENG":"I promise I will return the chest as soon as I take care of it.","TWN":"只要解決了那個問題，我保證會把箱子還給你。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"제가 그 말을 어떻게 믿고요?","JPN":"それを私が信じられると思いますか？","ENG":"And do you expect me to just take your word for it?","TWN":"但我要如何才能相信你呢？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"계약서 작성은 물론 슈-퍼 머신갑에서 나온 초합금 파편을 담보로 드리죠.","JPN":"契約書を書きましょう。そしてスーパーマシーン-甲-から剥がれ落ちた超合金の破片を担保として差し出します。","ENG":"We can draft a contract, and I will give you a piece of superalloy from the SUPER Machine G.A.P. as collateral.","TWN":"我不僅可以和你簽訂合約，還會以機械·我宇宙無敵帥的超合金碎片作為擔保。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"맹세하죠. 오르면 오르지. 보물의 값어치가 떨어지는 일은 절대로 없을 겁니다.","JPN":"誓います。お宝の価値は上昇することはあっても、決して下がることはありません。","ENG":"I give you my word. The value of the treasure will not decrease. In fact, it may go up.","TWN":"我發誓。只會漲，不會跌。寶物的價值絕對不會下降。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"으음. 어떻게 생각해요, 시그마?","JPN":"うーん。シグマはどう思いますか？","ENG":"Hmm. What do you think, Sigma?","TWN":"嗯……你怎麼看，西格瑪？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"응? 보물찾기는 끝났으니까 난 상관없어.","JPN":"え？　宝探しは終わったことだし、どっちでもいいよ。","ENG":"Hmm? Well, the treasure hunt is over, so I don't care.","TWN":"嗯？尋寶已經結束了，所以我沒關係。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"보물상자는 다음에 열어도 되니까… 지금은 유피가 하고 싶은 대로 해도 돼.","JPN":"宝箱を開けるのは……また今度でも構わないし、ユピの判断に任せる。","ENG":"I can open the chest another time, so... you can do whatever you want, Yuppie.","TWN":"寶箱下次再開也行。現在……悠菲想做什麼就去做吧。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하아… 실장님. 그건 평범한 보물이 아니라 아티팩트에요.","JPN":"はぁ……室長。これは普通のお宝ではなく、アーティファクトのようです。","ENG":"*Sigh* Chief. That's not an ordinary treasure. It's an Artifact.","TWN":"哀……室長，那個不是普通的寶物，而是人造神器。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_SUMMER_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"뭣 모르고 열었다가 큰일이라도 나면 어쩌려고 그래요?","JPN":"無闇に開けると、大変なことになるかもしれませんよ？","ENG":"You don't know what might happen upon opening it.","TWN":"你不知道就隨便打開，要是出了什麼大事該怎麼辦？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_SUMMER_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"좋아요. 그럼 셋 셀 테니 동시에 던지는 거예요?","JPN":"よし、じゃあ3つ数えるので、同時に投げましょう。","ENG":"Fine. Then I'll count to three, and we both throw it at the same time, okay?","TWN":"好吧，那我數到三，我們一起放手？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L2_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"걱정 마시죠. 진실된 거래야말로 비즈니스의 기본 아니겠습니까.","JPN":"安心してください。騙し合いのない取引こそが、ビジネスの根幹だと思うので。","ENG":"Don't worry. An honest trade is the foundation of good business.","TWN":"別擔心，誠信交易才是做生意的基本原則，不是嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"자, 그럼… 하나.","JPN":"いち。","ENG":"All right, then... One.","TWN":"好吧，那麼……一。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"둘…….","JPN":"に……","ENG":"Two...","TWN":"二……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"셋.","JPN":"さん。","ENG":"Three.","TWN":"三。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"어라.","JPN":"あれ。","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"혹시 넷에 여는 거였나요?","JPN":"4で開けるんでしたっけ？","ENG":"Were we going to open it at \\"four\\"?","TWN":"難道要數到四才開嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);